import re

file_path = 'curriculum/l2-uk-en/hist/persha-svitova.md'
with open(file_path, 'r', encoding='utf-8') as f:
    text = f.read()

dup_s3_1 = "Цей ентузіазм був справді безпрецедентним для тогочасної Європи. У той час як більшість народів імперії йшли на фронт з примусу, виконуючи суворий наказ своїх монархів, галицька молодь розглядала війну як свій історичний шанс. Вони прагнули власною кров'ю довести право українців на незалежність та державність. Легіон Українських Січових Стрільців від самого початку формувався не лише як суто військова одиниця, але й як глибоко ідейна, політична організація, кожен боєць якої розумів свою відповідальність перед майбутніми поколіннями. Ця висока ідейність дозволяла їм витримувати найважчі випробування окопного життя."
dup_s3_2 = "Цей феноменальний ентузіазм був справді безпрецедентним для тогочасної мілітаризованої Європи. У той час як більшість мобілізованих народів імперії йшли на кривавий фронт виключно з примусу, покірно виконуючи суворий наказ своїх монархів, галицька молодь розглядала цю війну як свій унікальний історичний шанс. Вони прагнули власною пролитою кров'ю беззаперечно довести законне право українців на незалежність та повноцінну державність. Легіон Українських Січових Стрільців від самого початку свого існування формувався не лише як суто військова тактична одиниця, але й як глибоко ідейна, потужна політична організація. Кожен боєць чітко розумів свою персональну відповідальність перед майбутніми поколіннями, і ця надзвичайно висока ідейність дозволяла їм стійко витримувати найважчі фізичні та психологічні випробування окопного життя."

dup_s4_1 = "Російські війська накочувалися нескінченними хвилями, змушуючи австрійські підрозділи до поспішної та неорганізованої евакуації. У цьому хаосі відступу саме на плечі українських добровольців лягло найважче завдання — забезпечувати ар'єргардні бої. Вони свідомо залишалися на передовій лінії вогню, прикриваючи відхід основних сил ціною власних життів. Цей період війни характеризувався надзвичайною інтенсивністю артилерійських дуелей та кавалерійських сутичок на відкритій місцевості. Кожен день приносив нові втрати, але водночас він загартовував тих, хто вижив, перетворюючи вчорашніх гімназистів на досвідчених фронтовиків, здатних швидко ухвалювати складні тактичні рішення у критичних ситуаціях. Цей безцінний бойовий досвід згодом стане вирішальним під час розбудови національних збройних сил в умовах революційного хаосу, коли колишні усуси візьмуть на себе відповідальність за формування регулярної армії молодої держави."
dup_s4_2 = "Російські імперські війська накочувалися нескінченними потужними хвилями, жорстоко змушуючи розгублені австрійські підрозділи до поспішної та абсолютно неорганізованої евакуації з позицій. У цьому суцільному кривавому хаосі стрімкого відступу саме на плечі молодих українських добровольців несподівано лягло найважче військове завдання — мужньо забезпечувати ар'єргардні бої. Вони свідомо та героїчно залишалися на передовій лінії смертоносного вогню, відчайдушно прикриваючи відхід основних сил ціною власних молодих життів. Цей трагічний період маневреної війни характеризувався надзвичайною інтенсивністю артилерійських дуелей та раптових кавалерійських сутичок на відкритій місцевості. Кожен новий день неминуче приносив усе нові болючі втрати, але водночас він жорстко загартовував тих, хто дивом вижив, стрімко перетворюючи вчорашніх недосвідчених гімназистів на загартованих досвідчених фронтовиків. Ці бійці тепер були здатні блискавично ухвалювати надзвичайно складні тактичні рішення у найкритичніших бойових ситуаціях. Здобутий безцінний бойовий досвід згодом стане вирішальним чинником під час подальшої розбудови національних збройних сил в екстремальних умовах революційного хаосу, коли саме ці колишні усуси впевнено візьмуть на себе історичну відповідальність за формування першої регулярної армії молодої української держави."

text = text.replace(dup_s3_1, "")
text = text.replace(dup_s3_2, "")
text = text.replace(dup_s4_1, "")
text = text.replace(dup_s4_2, "")

# remove possible standalone duplicates that became paragraphs
text = re.sub(r'\n\s*\n', '\n\n', text)
# strip spaces before newlines
text = '\n'.join([line.rstrip() for line in text.split('\n')])

# Ensure clean string replace
text = text.replace("справжня українська армія.", "справжня українська армія. " + dup_s3_2)
text = text.replace("масштабність трагедії Східного фронту.", "масштабність трагедії Східного фронту. " + dup_s4_2)

with open(file_path, 'w', encoding='utf-8') as f:
    f.write(text)

print("Cleaned up and reappended.")
